{
  "summary": "This paper formalizes the problem of Continual Knowledge Learning (CKL) for language models, proposing a benchmark suite and a novel FUAR metric to evaluate the trade-off between forgetting invariant knowledge and acquiring new or updated knowledge through continual pretraining. It adapts and evaluates several continual learning methods, finding parameter-expansion approaches most effective but highlighting challenges such as memory inefficiency and degradation over multiple update phases.",
  "strengths": [
    {
      "point": "Novel problem formulation and benchmark construction",
      "evidence": "The paper introduces CKL as a principled framework for continual knowledge updating in LMs and constructs new datasets (INVARIANT LAMA, UPDATED LAMA, NEW LAMA) with careful annotation and expert verification."
    },
    {
      "point": "Proposal of a novel evaluation metric (FUAR)",
      "evidence": "FUAR quantifies the trade-off between forgetting invariant knowledge and gaining updated or new knowledge, providing a meaningful measure for CKL performance."
    },
    {
      "point": "Comprehensive empirical evaluation across methods and architectures",
      "evidence": "The paper evaluates regularization, rehearsal, and parameter-expansion methods on encoder-decoder (T5) and decoder-only (GPT-2) models, including multiple update phases and downstream task transfer."
    },
    {
      "point": "Insightful analysis of training factors and CKL challenges",
      "evidence": "The study reveals that repeated data exposure causes forgetting, parameter-expansion methods are effective but memory-inefficient, and CKL methods degrade over multiple update phases."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparative analysis with knowledge editing methods",
      "evidence": "The paper does not adequately contrast CKL with fact-level knowledge editing approaches like MEMIT or ROME, missing discussion or experiments on their relative scope, complementarity, or integration."
    },
    {
      "point": "Lack of ablation and sensitivity analysis on the FUAR metric",
      "evidence": "No experiments explore alternative FUAR formulations, weighting schemes, or provide visualizations of FUAR dynamics, limiting confidence in its comprehensiveness."
    },
    {
      "point": "Limited transparency and potential bias in dataset annotation",
      "evidence": "Critical details such as inter-annotator agreement, annotation guidelines, and error analyses are omitted, and datasets focus solely on English news domain facts."
    },
    {
      "point": "Narrow baseline coverage excluding other continual learning paradigms",
      "evidence": "The evaluation omits meta-learning, dynamic architectures with selective freezing, and advanced replay strategies, limiting conclusiveness about parameter-expansion superiority."
    },
    {
      "point": "Suboptimal evaluation of rehearsal method Mix-Review",
      "evidence": "No ablations on sampling ratios or curriculum learning are conducted, and architecture- or dataset-dependent effects are not fully acknowledged."
    },
    {
      "point": "Absence of mechanistic analyses of catastrophic forgetting",
      "evidence": "The paper lacks layer-wise, token-level, or attribution studies to understand forgetting patterns and vulnerable knowledge types."
    },
    {
      "point": "Missing reproducibility details on hyperparameter tuning and data preprocessing",
      "evidence": "No specifics on tuning ranges, number of runs, variance, early stopping, or detailed \(D_1\) corpus filtering are provided."
    },
    {
      "point": "Clarity issues in FUAR explanation and invariant knowledge definition",
      "evidence": "FUAR lacks intuitive examples and visualizations; the operationalization of invariant knowledge is ambiguous without empirical verification."
    },
    {
      "point": "Unaddressed practical limitations such as memory inefficiency and computational costs",
      "evidence": "Parameter-expansion methods' memory growth is acknowledged but no mitigation strategies or computational cost analyses are presented."
    },
    {
      "point": "Limited generalizability due to domain, language, and architecture scope",
      "evidence": "Datasets are restricted to English news; only T5 and GPT-2 models are evaluated, excluding larger or multilingual LMs."
    },
    {
      "point": "No analysis of handling conflicting or contradictory knowledge",
      "evidence": "The study does not examine how CKL methods resolve conflicts between \(D_0\) and \(D_1\) knowledge."
    },
    {
      "point": "Lack of qualitative error analysis or failure mode examination",
      "evidence": "No examples or discussion of specific forgetting or update failures are provided."
    },
    {
      "point": "Limited exploration of long-term knowledge retention beyond two update phases",
      "evidence": "Only two sequential update phases are simulated, insufficient for real-world continual learning scenarios."
    },
    {
      "point": "Downstream task transfer results lack statistical significance testing",
      "evidence": "No confidence intervals or multiple runs are reported to establish robustness of improvements."
    }
  ],
  "questions": [
    {
      "question": "How does CKL compare empirically and conceptually with knowledge editing methods like MEMIT and ROME?",
      "motivation": "Understanding the relationship and potential integration between CKL and editing approaches is critical to position CKL's novelty and practical utility."
    },
    {
      "question": "Can the FUAR metric be further validated or improved through ablations and visualizations?",
      "motivation": "Ensuring FUAR reliably captures the forgetting-learning trade-off is essential for meaningful evaluation and method development."
    },
    {
      "question": "What strategies can mitigate memory inefficiency and degradation over multiple CKL update phases?",
      "motivation": "Addressing these practical limitations is vital for scalable, real-world deployment of CKL methods."
    },
    {
      "question": "How robust are the benchmark datasets across domains, languages, and annotation reliability?",
      "motivation": "Dataset generalizability and annotation quality directly impact the validity and applicability of CKL evaluations."
    },
    {
      "question": "How do CKL methods handle conflicting or contradictory knowledge between old and new corpora?",
      "motivation": "Conflict resolution is fundamental for reliable knowledge updating but remains unexplored."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
